/**
 * ArtecROBO ライントレーサー
 * ATmega168PA (Arduino互換ピン配置)
 *
 * ピン配置:
 *   D5 (OC0B) = 左モーターPWM
 *   D4        = 左モーター方向 (HIGH = 前進)
 *   D6 (OC0A) = 右モーターPWM
 *   D7        = 右モーター方向 (HIGH = 前進)
 *   D2 (PD2)  = 左フォトリフレクタ (LOW = 黒線)
 *   D3 (PD3)  = 中央フォトリフレクタ (LOW = 黒線)
 *   D8 (PB0)  = 右フォトリフレクタ (LOW = 黒線)
 */
#include <avr/io.h>

#define MOTOR_FAST 192  /* 75% デューティサイクル */
#define MOTOR_SLOW  80  /* 31% デューティサイクル */

static void motors_init(void) {
    /* D4, D5, D6, D7 を出力ピンに設定 */
    DDRD |= (1 << PD4) | (1 << PD5) | (1 << PD6) | (1 << PD7);
    /* D2, D3 を入力 + 内部プルアップ有効 */
    DDRD  &= ~((1 << PD2) | (1 << PD3));
    PORTD |=  (1 << PD2) | (1 << PD3);
    /* D8 を入力 + 内部プルアップ有効 */
    DDRB  &= ~(1 << PB0);
    PORTB |=  (1 << PB0);
    /* 方向ピン初期化: D4, D7 を HIGH (前進) に設定 */
    PORTD |= (1 << PD4) | (1 << PD7);
    /* Timer0: Fast PWM (OC0A=D6, OC0B=D5), 分周比64 (~980Hz) */
    TCCR0A = (1 << COM0A1) | (1 << COM0B1) | (1 << WGM01) | (1 << WGM00);
    TCCR0B = (1 << CS01) | (1 << CS00);
    OCR0A = 0;
    OCR0B = 0;
}

static void set_motors(uint8_t left, uint8_t right) {
    OCR0B = left;   /* 左モーター (D5 = OC0B) */
    OCR0A = right;  /* 右モーター (D6 = OC0A) */
}

int main(void) {
    motors_init();

    for (;;) {
        uint8_t pind = PIND;
        uint8_t pinb = PINB;

        /* LOW = 黒線上 (プルアップのため黒線でLOWになる) */
        uint8_t sL = !(pind & (1 << PD2));  /* 左センサー  */
        uint8_t sC = !(pind & (1 << PD3));  /* 中央センサー */
        uint8_t sR = !(pinb & (1 << PB0));  /* 右センサー  */

        if (sC) {
            if      (sL && !sR) set_motors(MOTOR_SLOW, MOTOR_FAST); /* 中央+左 → 右に傾き → 左補正 */
            else if (!sL && sR) set_motors(MOTOR_FAST, MOTOR_SLOW); /* 中央+右 → 左に傾き → 右補正 */
            else                set_motors(MOTOR_FAST, MOTOR_FAST); /* 中央のみ → 直進 */
        } else {
            if      (sL && !sR) set_motors(0,           MOTOR_FAST); /* 左のみ → 急左旋回 */
            else if (!sL && sR) set_motors(MOTOR_FAST,  0);          /* 右のみ → 急右旋回 */
            else                set_motors(MOTOR_SLOW,  MOTOR_SLOW); /* 検出なし → 低速直進 */
        }
    }
}
